import pandas as pd
from sentence_transformers import SentenceTransformer, util
from transformers import pipeline
from flask import Flask, request, jsonify
from flask_cors import CORS
from sklearn.feature_extraction.text import TfidfVectorizer
from sklearn.metrics.pairwise import cosine_similarity
import numpy as np

app = Flask(__name__)
CORS(app)

# Load company documents into vector database
docs = pd.read_csv('company_docs.csv')
model = SentenceTransformer('all-MiniLM-L6-v2')

doc_vectors = model.encode(docs['text'])

# Define LLM prompt generator function
def generate_llm_prompt(query, doc_vectors):
    query_vector = model.encode(query)
    similarities = cosine_similarity(query_vector.reshape(1, -1), doc_vectors).flatten()
    top_docs = np.argsort(-similarities)[:5]
    relevant_docs = docs.iloc[top_docs]['text'].tolist()
    return ' '.join(relevant_docs)

# Define API endpoint for user queries
@app.route('/query', methods=['POST'])
def query():
    data = request.get_json()
    query = data['query']
    prompt = generate_llm_prompt(query, doc_vectors)
    llm = pipeline('text-generation')
    response = llm(prompt, max_length=1024, num_return_sequences=1)[0]['generated_text']
    return jsonify({'response': response})

if __name__ == '__main__':
    app.run(debug=True)

